import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.stream.JsonWriter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.ArgumentCaptor;

import java.io.IOException;
import java.io.StringWriter;
import java.lang.reflect.Method;

public class JsonWriterTest {

  private StringWriter stringWriter;
  private JsonWriter jsonWriter;

  @BeforeEach
  public void setUp() {
    stringWriter = new StringWriter();
    jsonWriter = new JsonWriter(stringWriter);
  }

  @Test
  public void testValueTrueWritesTrue() throws IOException {
    JsonWriter spyWriter = spy(jsonWriter);

    // Spy writeDeferredName and beforeValue to do nothing (to isolate test)
    doNothing().when(spyWriter).writeDeferredName();
    doNothing().when(spyWriter).beforeValue();

    JsonWriter returned = spyWriter.value(true);

    assertSame(spyWriter, returned);
    assertEquals("true", stringWriter.toString());
    verify(spyWriter).writeDeferredName();
    verify(spyWriter).beforeValue();
  }

  @Test
  public void testValueFalseWritesFalse() throws IOException {
    JsonWriter spyWriter = spy(jsonWriter);

    doNothing().when(spyWriter).writeDeferredName();
    doNothing().when(spyWriter).beforeValue();

    JsonWriter returned = spyWriter.value(false);

    assertSame(spyWriter, returned);
    assertEquals("false", stringWriter.toString());
    verify(spyWriter).writeDeferredName();
    verify(spyWriter).beforeValue();
  }

  @Test
  public void testValueCallsPrivateMethodsCorrectly() throws Exception {
    // Use real JsonWriter with StringWriter to capture output
    JsonWriter writer = new JsonWriter(stringWriter);

    // Use reflection to invoke private writeDeferredName and beforeValue to verify no exceptions
    Method writeDeferredName = JsonWriter.class.getDeclaredMethod("writeDeferredName");
    writeDeferredName.setAccessible(true);

    Method beforeValue = JsonWriter.class.getDeclaredMethod("beforeValue");
    beforeValue.setAccessible(true);

    // Initially, stackSize is 0, so peek() would throw, so push a state to stack to avoid exceptions
    Method push = JsonWriter.class.getDeclaredMethod("push", int.class);
    push.setAccessible(true);
    push.invoke(writer, 6); // 6 is NONEMPTY_DOCUMENT

    // call private writeDeferredName and beforeValue to ensure coverage
    writeDeferredName.invoke(writer);
    beforeValue.invoke(writer);

    // Now call value(true) normally to ensure it writes "true"
    JsonWriter returned = writer.value(true);
    assertSame(writer, returned);
    assertEquals("true", stringWriter.toString());
  }

}
